		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy], bufferSize),
	}
}

func (m *mockEventChan) Chan() <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	return m.events
}

func (m *mockEventChan) Send(event resource.Event[*cilium_v2.CiliumNetworkPolicy]) {
	m.events <- event
}

func (m *mockEventChan) Close() {
	close(m.events)
}

// mockResource implements resource.Resource for testing
type mockResource struct {
	eventChan <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy]
}

func (m *mockResource) Events(ctx context.Context, opts ...resource.EventsOpt) <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	return m.eventChan
}

