// TestCheckQuota tests the CheckQuota method
func TestCheckQuota(t *testing.T) {
	tests := []struct {
		name              string
		maxPerNamespace   int
		namespace         string
		currentCount      int
		expectedErr       bool
		expectedErrStr    string
	}{
		{
			name:            "quota not exceeded",
			maxPerNamespace: 5,
			namespace:       "default",
			currentCount:    3,
			expectedErr:     false,
		},
		{
			name:            "quota exactly at limit",
			maxPerNamespace: 5,
			namespace:       "default",
			currentCount:    5,
			expectedErr:     true,
			expectedErrStr:  "policy quota exceeded",
		},
		{
			name:            "quota exceeded",
			maxPerNamespace: 5,
			namespace:       "default",
			currentCount:    6,
			expectedErr:     true,
			expectedErrStr:  "policy quota exceeded",
		},
		{
			name:            "unlimited quota (0)",
			maxPerNamespace: 0,
			namespace:       "default",
			currentCount:    100,
			expectedErr:     false,
		},
		{
			name:            "unknown namespace",
			maxPerNamespace: 5,
			namespace:       "unknown",
			currentCount:    0,
			expectedErr:     false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			controller := &PolicyQuotaController{
				log:                    logrus.NewEntry(logrus.New()),
				maxPerNamespace:        tt.maxPerNamespace,
				policyCountByNamespace: make(map[string]int),
			}

			// Set up the initial state
			if tt.currentCount > 0 {
				controller.policyCountByNamespace[tt.namespace] = tt.currentCount
			}

			err := controller.CheckQuota(tt.namespace)
			if tt.expectedErr {
				assert.Error(t, err)
				if tt.expectedErrStr != "" {
					assert.Contains(t, err.Error(), tt.expectedErrStr)
				}
			} else {
				assert.NoError(t, err)
			}
		})
	}
}

// TestGetNamespaceCount tests the GetNamespaceCount method
func TestGetNamespaceCount(t *testing.T) {
	controller := &PolicyQuotaController{
		log:                    logrus.NewEntry(logrus.New()),
		maxPerNamespace:        5,
		policyCountByNamespace: make(map[string]int),
	}

	// Test empty namespace
	count := controller.GetNamespaceCount("default")
	assert.Equal(t, 0, count)

	// Set up some counts
	controller.policyCountByNamespace["default"] = 3
	controller.policyCountByNamespace["kube-system"] = 10

	// Test existing namespaces
	assert.Equal(t, 3, controller.GetNamespaceCount("default"))
	assert.Equal(t, 10, controller.GetNamespaceCount("kube-system"))

	// Test non-existent namespace
	assert.Equal(t, 0, controller.GetNamespaceCount("non-existent"))
}

