// TestControllerRunWithEvents tests the Run method with event handling
func TestControllerRunWithEvents(t *testing.T) {
	mockChan := newMockEventChan(10)
	mockRes := &mockResource{
		eventChan: mockChan.Chan(),
	}

	controller := &PolicyQuotaController{
		log:                    logrus.NewEntry(logrus.New()),
		ciliumNetworkPolicies:  mockRes,
		maxPerNamespace:        5,
		policyCountByNamespace: make(map[string]int),
	}

	ctx, cancel := context.WithCancel(context.Background())

	// Run controller in a goroutine
	errChan := make(chan error, 1)
	go func() {
		errChan <- controller.Run(ctx)
	}()

	// Give controller time to start
	time.Sleep(50 * time.Millisecond)

	// Send an upsert event
	policy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
		Spec: &api.Rule{},
	}

	doneCall := make(chan error, 1)
	event := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Upsert,
		Object: policy,
		Done: func(err error) {
			doneCall <- err
		},
	}

	mockChan.Send(event)

	// Wait for Done to be called
	err := <-doneCall
	assert.NoError(t, err)

	// Verify count was incremented
	assert.Equal(t, 1, controller.GetNamespaceCount("default"))

	// Send a delete event
	event = resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Delete,
		Object: policy,
		Done: func(err error) {
			doneCall <- err
		},
	}

	mockChan.Send(event)

	// Wait for Done to be called
	err = <-doneCall
	assert.NoError(t, err)

	// Verify count was decremented
	assert.Equal(t, 0, controller.GetNamespaceCount("default"))

	// Cancel context and close the mock channel
	cancel()
	mockChan.Close()

	// Wait for controller to stop
	select {
	case err := <-errChan:
		assert.Error(t, err) // Should be context.Canceled or similar
	case <-time.After(1 * time.Second):
		t.Fatal("Controller did not stop in time")
	}
}

