// TestCheckQuota tests the CheckQuota method
func TestCheckQuota(t *testing.T) {
	tests := []struct {
		name              string
		maxPerNamespace   int
		namespace         string
		currentCount      int
		expectedErr       bool
		expectedErrStr    string
	}{
		{
			name:            "quota not exceeded",
			maxPerNamespace: 5,
			namespace:       "default",
			currentCount:    3,
			expectedErr:     false,
		},
		{
			name:            "quota exactly at limit",
			maxPerNamespace: 5,
			namespace:       "default",
			currentCount:    5,
			expectedErr:     true,
			expectedErrStr:  "policy quota exceeded",
		},
		{
			name:            "quota exceeded",
			maxPerNamespace: 5,
			namespace:       "default",
			currentCount:    6,
			expectedErr:     true,
			expectedErrStr:  "policy quota exceeded",
		},
		{
			name:            "unlimited quota (0)",
			maxPerNamespace: 0,
			namespace:       "default",
			currentCount:    100,
			expectedErr:     false,
		},
		{
			name:            "unknown namespace",
			maxPerNamespace: 5,
			namespace:       "unknown",
			currentCount:    0,
			expectedErr:     false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			controller := &PolicyQuotaController{
				log:                    logrus.NewEntry(logrus.New()),
				maxPerNamespace:        tt.maxPerNamespace,
				policyCountByNamespace: make(map[string]int),
				policyKeys:             make(map[string]struct{}),
			}

			// Set up the initial state
			if tt.currentCount > 0 {
				controller.policyCountByNamespace[tt.namespace] = tt.currentCount
			}

			err := controller.CheckQuota(tt.namespace)
			if tt.expectedErr {
				assert.Error(t, err)
				if tt.expectedErrStr != "" {
					assert.Contains(t, err.Error(), tt.expectedErrStr)
				}
			} else {
				assert.NoError(t, err)
			}
		})
	}
}

// TestGetNamespaceCount tests the GetNamespaceCount method
func TestGetNamespaceCount(t *testing.T) {
	controller := &PolicyQuotaController{
		log:                    logrus.NewEntry(logrus.New()),
		maxPerNamespace:        5,
		policyCountByNamespace: make(map[string]int),
		policyKeys:             make(map[string]struct{}),
	}

	// Test empty namespace
	count := controller.GetNamespaceCount("default")
	assert.Equal(t, 0, count)

	// Set up some counts
	controller.policyCountByNamespace["default"] = 3
	controller.policyCountByNamespace["kube-system"] = 10

	// Test existing namespaces
	assert.Equal(t, 3, controller.GetNamespaceCount("default"))
	assert.Equal(t, 10, controller.GetNamespaceCount("kube-system"))

	// Test non-existent namespace
	assert.Equal(t, 0, controller.GetNamespaceCount("non-existent"))
}

// TestOnPolicyUpsert tests the onPolicyUpsert method
func TestOnPolicyUpsert(t *testing.T) {
	controller := &PolicyQuotaController{
		log:                    logrus.NewEntry(logrus.New()),
		maxPerNamespace:        5,
		policyCountByNamespace: make(map[string]int),
		policyKeys:             make(map[string]struct{}),
	}

	policy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
		Spec: &api.Rule{},
	}

	err := controller.onPolicyUpsert(policy)
	assert.NoError(t, err)
	assert.Equal(t, 1, controller.policyCountByNamespace["default"])

	// Upsert again (simulating an update) - should NOT increment
	err = controller.onPolicyUpsert(policy)
	assert.NoError(t, err)
	assert.Equal(t, 1, controller.policyCountByNamespace["default"])

	// Upsert a different policy
	policy2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy-2",
			Namespace: "default",
		},
		Spec: &api.Rule{},
	}
	err = controller.onPolicyUpsert(policy2)
	assert.NoError(t, err)
	assert.Equal(t, 2, controller.policyCountByNamespace["default"])
}

// TestOnPolicyDelete tests the onPolicyDelete method
func TestOnPolicyDelete(t *testing.T) {
	controller := &PolicyQuotaController{
		log:                    logrus.NewEntry(logrus.New()),
		maxPerNamespace:        5,
		policyCountByNamespace: make(map[string]int),
		policyKeys:             make(map[string]struct{}),
	}

	policy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
		Spec: &api.Rule{},
	}

	policyKey := "default/test-policy"

	// Set up initial count and policy key
	controller.policyCountByNamespace["default"] = 2
	controller.policyKeys[policyKey] = struct{}{}

	err := controller.onPolicyDelete(policy)
	assert.NoError(t, err)
	assert.Equal(t, 1, controller.policyCountByNamespace["default"])
	_, exists := controller.policyKeys[policyKey]
	assert.False(t, exists)

	// Set up another policy
	controller.policyCountByNamespace["default"] = 1
	controller.policyKeys[policyKey] = struct{}{}

	// Delete again
	err = controller.onPolicyDelete(policy)
	assert.NoError(t, err)
	assert.Equal(t, 0, controller.policyCountByNamespace["default"])

	// Namespace should be cleaned up
	_, exists = controller.policyCountByNamespace["default"]
	assert.False(t, exists)

	// Try to delete a policy that's not tracked
	policy2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "unknown-policy",
			Namespace: "default",
		},
		Spec: &api.Rule{},
	}
	err = controller.onPolicyDelete(policy2)
	assert.NoError(t, err)
}

// TestControllerRunWithEvents tests the Run method with event handling
func TestControllerRunWithEvents(t *testing.T) {
	mockChan := newMockEventChan(10)
	mockRes := &mockResource{
		eventChan: mockChan.Chan(),
	}

	controller := &PolicyQuotaController{
		log:                    logrus.NewEntry(logrus.New()),
		ciliumNetworkPolicies:  mockRes,
		maxPerNamespace:        5,
		policyCountByNamespace: make(map[string]int),
	}

	ctx, cancel := context.WithCancel(context.Background())

	// Run controller in a goroutine
	errChan := make(chan error, 1)
	go func() {
		errChan <- controller.Run(ctx)
	}()

	// Give controller time to start
	time.Sleep(50 * time.Millisecond)

	// Send an upsert event
	policy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
		Spec: &api.Rule{},
	}

	doneCall := make(chan error, 1)
	event := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Upsert,
		Object: policy,
		Done: func(err error) {
			doneCall <- err
		},
	}

	mockChan.Send(event)

	// Wait for Done to be called
	err := <-doneCall
	assert.NoError(t, err)

	// Verify count was incremented
	assert.Equal(t, 1, controller.GetNamespaceCount("default"))

	// Send a delete event
	event = resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Delete,
		Object: policy,
		Done: func(err error) {
			doneCall <- err
		},
	}

	mockChan.Send(event)

	// Wait for Done to be called
	err = <-doneCall
	assert.NoError(t, err)

	// Verify count was decremented
	assert.Equal(t, 0, controller.GetNamespaceCount("default"))

	// Cancel context and close the mock channel
	cancel()
	mockChan.Close()

	// Wait for controller to stop
	select {
	case err := <-errChan:
		assert.Error(t, err) // Should be context.Canceled or similar
	case <-time.After(1 * time.Second):
		t.Fatal("Controller did not stop in time")
	}
}

